1	package runner
2	
3	import (
4		"bytes"
5		"context"
6		"fmt"
7		"os"
8		"os/exec"
9		"strings"
10		"sync"
11		"time"
12	
13		"github.com/CosmoLabs-org/cosmo-smoke/internal/reporter"
14		"github.com/CosmoLabs-org/cosmo-smoke/internal/schema"
15	)
16	
17	// RunOptions controls test execution behavior.
18	type RunOptions struct {
19		Tags        []string
20		ExcludeTags []string
21		FailFast    bool
22		DryRun      bool
23		Timeout     time.Duration // per-test override (0 = use config)
24	}
25	
26	// SuiteResult holds the aggregate outcome.
27	type SuiteResult struct {
28		Project         string
29		Total           int
30		Passed          int
31		Failed          int
32		Skipped         int
33		AllowedFailures int
34		Duration        time.Duration
35		Tests           []TestResult
36	}
37	
38	// TestResult holds one test's outcome.
39	type TestResult struct {
40		Name           string
41		Passed         bool
42		Skipped        bool
43		AllowedFailure bool // true if test failed but allow_failure was set
44		Duration       time.Duration
45		Assertions     []AssertionResult
46		Error          error
47		Attempts       int // number of attempts made (1 = no retry)
48	}
49	
50	// Runner executes smoke tests from a config.
51	type Runner struct {
52		Config    *schema.SmokeConfig
53		Reporter  reporter.Reporter
54		ConfigDir string
55	}
56	
57	// Run executes all tests per the options and returns the suite result.
58	func (r *Runner) Run(opts RunOptions) (*SuiteResult, error) {
59		start := time.Now()
60	
61		// Run prerequisites
62		if len(r.Config.Prereqs) > 0 {
63			timeout := r.Config.Settings.Timeout.Duration
64			if timeout == 0 {
65				timeout = 30 * time.Second
66			}
67			results := CheckPrerequisites(r.Config.Prereqs, timeout)
68			for _, pr := range results {
69				r.Reporter.PrereqStart(pr.Name)
70				r.Reporter.PrereqResult(reporter.PrereqResultData{
71					Name:   pr.Name,
72					Passed: pr.Passed,
73					Output: pr.Output,
74					Hint:   pr.Hint,
75					Error:  pr.Error,
76				})
77			}
78			// Check for prereq failures
79			for _, pr := range results {
80				if !pr.Passed {
81					return nil, fmt.Errorf("prerequisite %q failed: %v", pr.Name, pr.Error)
82				}
83			}
84		}
85	
86		// Filter tests by tags
87		tests := filterTests(r.Config.Tests, opts.Tags, opts.ExcludeTags)
88	
89		suite := &SuiteResult{
90			Project: r.Config.Project,
91			Total:   len(tests),
92		}
93	
94		failFast := opts.FailFast || r.Config.Settings.FailFast
95	
96		if r.Config.Settings.Parallel && !failFast {
97			r.runParallel(tests, opts, suite)
98		} else {
99			r.runSequential(tests, opts, suite, failFast)
100		}
101	
102		suite.Duration = time.Since(start)
103	
104		// Report summary
105		r.Reporter.Summary(reporter.SuiteResultData{
106			Project:         suite.Project,
107			Total:           suite.Total,
108			Passed:          suite.Passed,
109			Failed:          suite.Failed,
110			Skipped:         suite.Skipped,
111			AllowedFailures: suite.AllowedFailures,
112			Duration:        suite.Duration,
113		})
114	
115		return suite, nil
116	}
117	
118	func (r *Runner) runSequential(tests []schema.Test, opts RunOptions, suite *SuiteResult, failFast bool) {
119		stopped := false
120		for _, t := range tests {
121			if stopped {
122				tr := TestResult{Name: t.Name, Skipped: true}
123				suite.Tests = append(suite.Tests, tr)
124				suite.Skipped++
125				r.Reporter.TestStart(t.Name)
126				r.Reporter.TestResult(reporter.TestResultData{Name: t.Name, Skipped: true})
127				continue
128			}
129	
130			tr := r.runTest(t, opts)
131			suite.Tests = append(suite.Tests, tr)
132			if tr.Passed {
133				suite.Passed++
134			} else if tr.Skipped {
135				suite.Skipped++
136			} else if tr.AllowedFailure {
137				suite.AllowedFailures++
138			} else {
139				suite.Failed++
140				if failFast {
141					stopped = true
142				}
143			}
144		}
145	}
146	
147	func (r *Runner) runParallel(tests []schema.Test, opts RunOptions, suite *SuiteResult) {
148		results := make([]TestResult, len(tests))
149		var wg sync.WaitGroup
150	
151		for i, t := range tests {
152			wg.Add(1)
153			go func(idx int, test schema.Test) {
154				defer wg.Done()
155				results[idx] = r.runTest(test, opts)
156			}(i, t)
157		}
158		wg.Wait()
159	
160		for _, tr := range results {
161			suite.Tests = append(suite.Tests, tr)
162			if tr.Passed {
163				suite.Passed++
164			} else if tr.Skipped {
165				suite.Skipped++
166			} else if tr.AllowedFailure {
167				suite.AllowedFailures++
168			} else {
169				suite.Failed++
170			}
171		}
172	}
173	
174	func (r *Runner) runTest(t schema.Test, opts RunOptions) TestResult {
175		if t.Retry == nil || t.Retry.Count <= 1 {
176			res := r.runTestOnce(t, opts)
177			if res.Attempts == 0 {
178				res.Attempts = 1
179			}
180			return res
181		}
182		var last TestResult
183		backoff := t.Retry.Backoff.Duration
