482		}
483	
484		var filtered []schema.Test
485		for _, t := range tests {
486			if len(include) > 0 && !hasAnyTag(t.Tags, include) {
487				continue
488			}
489			if len(exclude) > 0 && hasAnyTag(t.Tags, exclude) {
490				continue
491			}
492			filtered = append(filtered, t)
493		}
494		return filtered
495	}
496	
497	func hasAnyTag(tags, targets []string) bool {
498		for _, tag := range tags {
499			for _, target := range targets {
500				if strings.EqualFold(tag, target) {
501					return true
502				}
503			}
504		}
505		return false
506	}
