508	// shouldSkip evaluates skip_if conditions and returns true if the test should be skipped.
509	func shouldSkip(si *schema.SkipIf, configDir string) bool {
510		if si == nil {
511			return false
512		}
513		if si.EnvUnset != "" {
514			if _, ok := os.LookupEnv(si.EnvUnset); !ok {
515				return true
516			}
517		}
518		if si.EnvEquals != nil {
519			if val, ok := os.LookupEnv(si.EnvEquals.Var); ok && val == si.EnvEquals.Value {
520				return true
521			}
522		}
523		if si.FileMissing != "" {
524			path := si.FileMissing
525			if !strings.HasPrefix(path, "/") {
526				path = configDir + "/" + path
527			}
528			if _, err := os.Stat(path); os.IsNotExist(err) {
529				return true
530			}
531		}
532		return false
533	}
