		if e := t.Expect.WebSocket; e != nil {
			if e.URL == "" {
				errs = append(errs, fmt.Sprintf("%s: websocket.url is required", prefix))
			} else if !strings.HasPrefix(e.URL, "ws://") && !strings.HasPrefix(e.URL, "wss://") {
