129	// CheckProcessRunning verifies that a named process is currently running on the host.
130	// Uses exact process-name matching (pgrep -x on Unix, CSV-parsed tasklist on Windows).
131	// Bounded by a 2s timeout to prevent hangs.
132	func CheckProcessRunning(name string) AssertionResult {
133		if name == "" {
134			return AssertionResult{Type: "process_running", Expected: name, Actual: "empty name", Passed: false}
135		}
136		ctx, cancel := context.WithTimeout(context.Background(), 2*time.Second)
137		defer cancel()
138		if runtime.GOOS == "windows" {
139			filter := fmt.Sprintf("IMAGENAME eq %s", name)
140			out, err := exec.CommandContext(ctx, "tasklist", "/FI", filter, "/FO", "CSV", "/NH").Output()
141			if err != nil {
142				return AssertionResult{Type: "process_running", Expected: name, Actual: "lookup error", Passed: false}
143			}
144			if !strings.Contains(string(out), "\""+name) {
145				return AssertionResult{Type: "process_running", Expected: name, Actual: "not found", Passed: false}
146			}
147			return AssertionResult{Type: "process_running", Expected: name, Actual: "running", Passed: true}
148		}
149		out, err := exec.CommandContext(ctx, "pgrep", "-x", name).Output()
150		if err != nil {
151			if ee, ok := err.(*exec.ExitError); ok && ee.ExitCode() == 1 {
152				return AssertionResult{Type: "process_running", Expected: name, Actual: "not found", Passed: false}
153			}
154			return AssertionResult{Type: "process_running", Expected: name, Actual: "lookup error: " + err.Error(), Passed: false}
155		}
156		if len(out) == 0 {
157			return AssertionResult{Type: "process_running", Expected: name, Actual: "not found", Passed: false}
158		}
159		return AssertionResult{Type: "process_running", Expected: name, Actual: strings.TrimSpace(string(out)), Passed: true}
160	}
