191	// CheckHTTP performs an HTTP request and returns assertion results for status, body, and headers.
192	func CheckHTTP(check *schema.HTTPCheck) []AssertionResult {
193		var results []AssertionResult
194	
195		// Default method to GET
196		method := check.Method
197		if method == "" {
198			method = "GET"
199		}
200	
201		// Set timeout (default 10s)
202		timeout := 10 * time.Second
203		if check.Timeout.Duration > 0 {
204			timeout = check.Timeout.Duration
205		}
206	
207		client := &http.Client{Timeout: timeout}
208	
209		// Build request
210		var bodyReader io.Reader
211		if check.Body != "" {
212			bodyReader = strings.NewReader(check.Body)
213		}
214	
215		req, err := http.NewRequest(method, check.URL, bodyReader)
216		if err != nil {
217			return []AssertionResult{{
218				Type:     "http_request",
219				Expected: check.URL,
220				Actual:   fmt.Sprintf("invalid request: %v", err),
221				Passed:   false,
222			}}
223		}
224	
225		// Add headers
226		for k, v := range check.Headers {
227			req.Header.Set(k, v)
228		}
229	
230		// Execute request
231		resp, err := client.Do(req)
232		if err != nil {
233			return []AssertionResult{{
234				Type:     "http_request",
235				Expected: check.URL,
236				Actual:   fmt.Sprintf("request failed: %v", err),
237				Passed:   false,
238			}}
239		}
240		defer resp.Body.Close()
241	
242		// Read body
243		body, err := io.ReadAll(resp.Body)
244		if err != nil {
245			return []AssertionResult{{
246				Type:     "http_body",
247				Expected: "readable body",
248				Actual:   fmt.Sprintf("failed to read body: %v", err),
249				Passed:   false,
250			}}
251		}
252		bodyStr := string(body)
253	
254		// Check status code
255		if check.StatusCode != nil {
256			results = append(results, AssertionResult{
257				Type:     "http_status",
258				Expected: fmt.Sprintf("%d", *check.StatusCode),
259				Actual:   fmt.Sprintf("%d", resp.StatusCode),
260				Passed:   resp.StatusCode == *check.StatusCode,
261			})
262		}
263	
264		// Check body contains
265		if check.BodyContains != "" {
266			results = append(results, AssertionResult{
267				Type:     "http_body_contains",
268				Expected: check.BodyContains,
269				Actual:   bodyStr,
270				Passed:   strings.Contains(bodyStr, check.BodyContains),
271			})
272		}
273	
274		// Check body matches regex
275		if check.BodyMatches != "" {
276			matched, err := regexp.MatchString(check.BodyMatches, bodyStr)
277			if err != nil {
278				results = append(results, AssertionResult{
279					Type:     "http_body_matches",
280					Expected: check.BodyMatches,
281					Actual:   fmt.Sprintf("invalid regex: %v", err),
282					Passed:   false,
283				})
284			} else {
285				results = append(results, AssertionResult{
286					Type:     "http_body_matches",
287					Expected: check.BodyMatches,
288					Actual:   bodyStr,
289					Passed:   matched,
290				})
291			}
292		}
293	
294		// Check header contains
295		for k, v := range check.HeaderContains {
296			actual := resp.Header.Get(k)
297			results = append(results, AssertionResult{
298				Type:     "http_header_contains",
299				Expected: fmt.Sprintf("%s: %s", k, v),
300				Actual:   fmt.Sprintf("%s: %s", k, actual),
301				Passed:   strings.Contains(actual, v),
302			})
303		}
304	
305		return results
306	}
