308	// CheckSSLCert dials host:port over TLS and validates the certificate chain,
309	// expiry, and days-remaining threshold.
310	func CheckSSLCert(check *schema.SSLCertCheck) AssertionResult {
311		port := check.Port
312		if port == 0 {
313			port = 443
314		}
315		addr := fmt.Sprintf("%s:%d", check.Host, port)
316		conf := &tls.Config{
317			ServerName:         check.Host,
318			InsecureSkipVerify: check.AllowSelfSigned, //nolint:gosec -- opt-in per AllowSelfSigned flag
319		}
320		dialer := &net.Dialer{Timeout: 10 * time.Second}
321		conn, err := tls.DialWithDialer(dialer, "tcp", addr, conf)
322		if err != nil {
323			return AssertionResult{Type: "ssl_cert", Expected: addr, Actual: err.Error(), Passed: false}
324		}
325		defer conn.Close()
326		certs := conn.ConnectionState().PeerCertificates
327		if len(certs) == 0 {
328			return AssertionResult{Type: "ssl_cert", Expected: addr, Actual: "no peer certificate", Passed: false}
329		}
330		leaf := certs[0]
331		now := time.Now()
332		if now.After(leaf.NotAfter) {
333			return AssertionResult{
334				Type:     "ssl_cert",
335				Expected: "valid cert",
336				Actual:   "expired on " + leaf.NotAfter.Format("2006-01-02"),
337				Passed:   false,
338			}
339		}
340		if check.MinDaysRemaining > 0 {
341			daysLeft := int(leaf.NotAfter.Sub(now).Hours() / 24)
342			if daysLeft < check.MinDaysRemaining {
343				return AssertionResult{
344					Type:     "ssl_cert",
345					Expected: fmt.Sprintf(">= %d days", check.MinDaysRemaining),
346					Actual:   fmt.Sprintf("%d days", daysLeft),
347					Passed:   false,
348				}
349			}
350		}
351		return AssertionResult{
352			Type:     "ssl_cert",
353			Expected: addr,
354			Actual:   fmt.Sprintf("valid, expires %s", leaf.NotAfter.Format("2006-01-02")),
355			Passed:   true,
356		}
357	}
