359	// CheckJSONField extracts a field from JSON and validates it against equals/contains/matches.
360	func CheckJSONField(jsonStr string, check *schema.JSONFieldCheck) []AssertionResult {
361		var results []AssertionResult
362	
363		// Check if JSON is valid
364		if !gjson.Valid(jsonStr) {
365			return []AssertionResult{{
366				Type:     "json_field",
367				Expected: check.Path,
368				Actual:   "invalid JSON",
369				Passed:   false,
370			}}
371		}
372	
373		// Extract the field value
374		result := gjson.Get(jsonStr, check.Path)
375		if !result.Exists() {
376			return []AssertionResult{{
377				Type:     "json_field",
378				Expected: check.Path,
379				Actual:   "field not found",
380				Passed:   false,
381			}}
382		}
383	
384		actual := result.String()
385	
386		// Check equals
387		if check.Equals != "" {
388			results = append(results, AssertionResult{
389				Type:     "json_field_equals",
390				Expected: check.Equals,
391				Actual:   actual,
392				Passed:   actual == check.Equals,
393			})
394		}
395	
396		// Check contains
397		if check.Contains != "" {
398			results = append(results, AssertionResult{
399				Type:     "json_field_contains",
400				Expected: check.Contains,
401				Actual:   actual,
402				Passed:   strings.Contains(actual, check.Contains),
403			})
404		}
405	
406		// Check matches
407		if check.Matches != "" {
408			matched, err := regexp.MatchString(check.Matches, actual)
409			if err != nil {
410				results = append(results, AssertionResult{
411					Type:     "json_field_matches",
412					Expected: check.Matches,
413					Actual:   fmt.Sprintf("invalid regex: %v", err),
414					Passed:   false,
415				})
416			} else {
417				results = append(results, AssertionResult{
418					Type:     "json_field_matches",
419					Expected: check.Matches,
420					Actual:   actual,
421					Passed:   matched,
422				})
423			}
424		}
425	
426		return results
427	}
