429	// CheckRedisPing issues a PING to a Redis server and expects +PONG.
430	func CheckRedisPing(check *schema.RedisCheck) AssertionResult {
431		host := check.Host
432		if host == "" {
433			host = "localhost"
434		}
435		port := check.Port
436		if port == 0 {
437			port = 6379
438		}
439		addr := fmt.Sprintf("%s:%d", host, port)
440		conn, err := net.DialTimeout("tcp", addr, 5*time.Second)
441		if err != nil {
442			return AssertionResult{Type: "redis_ping", Expected: addr, Actual: err.Error(), Passed: false}
443		}
444		defer conn.Close()
445		conn.SetDeadline(time.Now().Add(5 * time.Second)) //nolint:errcheck
446	
447		// Optional AUTH
448		if check.Password != "" {
449			authCmd := fmt.Sprintf("*2\r\n$4\r\nAUTH\r\n$%d\r\n%s\r\n", len(check.Password), check.Password)
450			if _, err := conn.Write([]byte(authCmd)); err != nil {
451				return AssertionResult{Type: "redis_ping", Expected: addr, Actual: "auth write error: " + err.Error(), Passed: false}
452			}
453			buf := make([]byte, 128)
454			n, _ := conn.Read(buf)
455			if !strings.HasPrefix(string(buf[:n]), "+OK") {
456				return AssertionResult{Type: "redis_ping", Expected: "+OK", Actual: strings.TrimSpace(string(buf[:n])), Passed: false}
457			}
458		}
459	
460		if _, err := conn.Write([]byte("*1\r\n$4\r\nPING\r\n")); err != nil {
461			return AssertionResult{Type: "redis_ping", Expected: addr, Actual: err.Error(), Passed: false}
462		}
463		buf := make([]byte, 64)
464		n, err := conn.Read(buf)
465		if err != nil {
466			return AssertionResult{Type: "redis_ping", Expected: "+PONG", Actual: err.Error(), Passed: false}
467		}
468		reply := strings.TrimSpace(string(buf[:n]))
469		if !strings.HasPrefix(reply, "+PONG") {
470			return AssertionResult{Type: "redis_ping", Expected: "+PONG", Actual: reply, Passed: false}
471		}
472		return AssertionResult{Type: "redis_ping", Expected: addr, Actual: "PONG", Passed: true}
473	}
