475	// CheckMemcachedVersion issues `version` to Memcached and expects a VERSION line.
476	func CheckMemcachedVersion(check *schema.MemcachedCheck) AssertionResult {
477		host := check.Host
478		if host == "" {
479			host = "localhost"
480		}
481		port := check.Port
482		if port == 0 {
483			port = 11211
484		}
485		addr := fmt.Sprintf("%s:%d", host, port)
486		conn, err := net.DialTimeout("tcp", addr, 5*time.Second)
487		if err != nil {
488			return AssertionResult{Type: "memcached_version", Expected: addr, Actual: err.Error(), Passed: false}
489		}
490		defer conn.Close()
491		conn.SetDeadline(time.Now().Add(5 * time.Second)) //nolint:errcheck
492	
493		if _, err := conn.Write([]byte("version\r\n")); err != nil {
494			return AssertionResult{Type: "memcached_version", Expected: addr, Actual: err.Error(), Passed: false}
495		}
496		buf := make([]byte, 128)
497		n, err := conn.Read(buf)
498		if err != nil {
499			return AssertionResult{Type: "memcached_version", Expected: "VERSION", Actual: err.Error(), Passed: false}
500		}
501		reply := strings.TrimSpace(string(buf[:n]))
502		if !strings.HasPrefix(reply, "VERSION") {
