508	// CheckPostgresPing sends an SSLRequest to a Postgres server and verifies a protocol-valid response.
509	func CheckPostgresPing(check *schema.PostgresCheck) AssertionResult {
510		host := check.Host
511		if host == "" {
512			host = "localhost"
513		}
514		port := check.Port
515		if port == 0 {
516			port = 5432
517		}
518		addr := fmt.Sprintf("%s:%d", host, port)
519		conn, err := net.DialTimeout("tcp", addr, 5*time.Second)
520		if err != nil {
521			return AssertionResult{Type: "postgres_ping", Expected: addr, Actual: err.Error(), Passed: false}
522		}
523		defer conn.Close()
524		conn.SetDeadline(time.Now().Add(5 * time.Second)) //nolint:errcheck
525	
526		// SSLRequest message: int32 length (8), int32 code (80877103)
527		// Bytes: 00 00 00 08 04 D2 16 2F
528		sslReq := []byte{0x00, 0x00, 0x00, 0x08, 0x04, 0xD2, 0x16, 0x2F}
529		if _, err := conn.Write(sslReq); err != nil {
530			return AssertionResult{Type: "postgres_ping", Expected: addr, Actual: "write error: " + err.Error(), Passed: false}
531		}
532		buf := make([]byte, 1)
533		n, err := conn.Read(buf)
534		if err != nil || n == 0 {
535			return AssertionResult{Type: "postgres_ping", Expected: "S or N", Actual: fmt.Sprintf("read error: %v", err), Passed: false}
536		}
537		reply := buf[0]
538		// 'S' = SSL supported, 'N' = SSL not supported, 'E' = error message follows (still valid postgres)
539		if reply == 'S' || reply == 'N' || reply == 'E' {
540			return AssertionResult{Type: "postgres_ping", Expected: addr, Actual: string(reply), Passed: true}
541		}
542		return AssertionResult{Type: "postgres_ping", Expected: "S/N/E", Actual: fmt.Sprintf("0x%02x", reply), Passed: false}
543	}
544	
545	// CheckMySQLPing verifies a MySQL server sends a valid v10 handshake packet on connection.
546	func CheckMySQLPing(check *schema.MySQLCheck) AssertionResult {
547		host := check.Host
548		if host == "" {
549			host = "localhost"
550		}
551		port := check.Port
552		if port == 0 {
553			port = 3306
554		}
555		addr := fmt.Sprintf("%s:%d", host, port)
556		conn, err := net.DialTimeout("tcp", addr, 5*time.Second)
557		if err != nil {
558			return AssertionResult{Type: "mysql_ping", Expected: addr, Actual: err.Error(), Passed: false}
559		}
560		defer conn.Close()
561		conn.SetDeadline(time.Now().Add(5 * time.Second)) //nolint:errcheck
562	
563		// MySQL server immediately sends a handshake packet:
564		// [3 bytes: payload length][1 byte: sequence id][payload starts with 1 byte: protocol version]
565		// Protocol version 10 (0x0a) is "v10", the current universally-used version.
566		hdr := make([]byte, 5)
567		n, err := conn.Read(hdr)
568		if err != nil || n < 5 {
569			return AssertionResult{Type: "mysql_ping", Expected: "handshake", Actual: fmt.Sprintf("read error: %v (n=%d)", err, n), Passed: false}
570		}
571		protocolVersion := hdr[4]
572		if protocolVersion != 0x0a {
573			return AssertionResult{Type: "mysql_ping", Expected: "protocol v10 (0x0a)", Actual: fmt.Sprintf("0x%02x", protocolVersion), Passed: false}
574		}
575		return AssertionResult{Type: "mysql_ping", Expected: addr, Actual: "v10", Passed: true}
576	}
577	
578	// isDockerAvailable returns true if the docker daemon is reachable.
579	func isDockerAvailable() bool {
580		ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
581		defer cancel()
582		return exec.CommandContext(ctx, "docker", "info").Run() == nil
583	}
584	
585	// CheckDockerContainerRunning checks if a named Docker container is running.
586	func CheckDockerContainerRunning(check *schema.DockerContainerCheck) AssertionResult {
587		ctx, cancel := context.WithTimeout(context.Background(), 10*time.Second)
588		defer cancel()
589		out, err := exec.CommandContext(ctx, "docker", "inspect", "--format={{.State.Running}}", check.Name).Output()
590		if err != nil {
591			return AssertionResult{Type: "docker_container_running", Expected: check.Name, Actual: "container not found or docker unavailable: " + err.Error(), Passed: false}
592		}
593		running := strings.TrimSpace(string(out))
594		if running != "true" {
595			return AssertionResult{Type: "docker_container_running", Expected: "true", Actual: running, Passed: false}
596		}
597		return AssertionResult{Type: "docker_container_running", Expected: check.Name, Actual: "running", Passed: true}
598	}
599	
600	// CheckDockerImageExists checks if a Docker image exists locally.
601	func CheckDockerImageExists(check *schema.DockerImageCheck) AssertionResult {
602		ctx, cancel := context.WithTimeout(context.Background(), 10*time.Second)
603		defer cancel()
604		err := exec.CommandContext(ctx, "docker", "image", "inspect", check.Image).Run()
605		if err != nil {
606			return AssertionResult{Type: "docker_image_exists", Expected: check.Image, Actual: "image not found or docker unavailable: " + err.Error(), Passed: false}
607		}
608		return AssertionResult{Type: "docker_image_exists", Expected: check.Image, Actual: "exists", Passed: true}
609	}
610	
611	// httpReachable makes an HTTP GET request and returns the status code,
612	// response time, and any error. expectedStatus=0 means any 2xx passes.
613	func httpReachable(url string, timeout time.Duration, expectedStatus int) (statusCode int, elapsed time.Duration, err error) {
614		if timeout == 0 {
615			timeout = 5 * time.Second
616		}
617		client := &http.Client{Timeout: timeout}
618		start := time.Now()
619		resp, err := client.Get(url)
620		elapsed = time.Since(start)
621		if err != nil {
622			return 0, elapsed, err
623		}
624		defer resp.Body.Close()
625		return resp.StatusCode, elapsed, nil
626	}
627	
628	// is2xx returns true if the status code is in the 200-299 range.
629	func is2xx(code int) bool {
630		return code >= 200 && code <= 299
631	}
632	
633	// CheckURLReachable verifies an HTTP/HTTPS endpoint is accessible.
634	func CheckURLReachable(check *schema.URLReachableCheck) AssertionResult {
635		statusCode, elapsed, err := httpReachable(check.URL, check.Timeout.Duration, 0)
636		if err != nil {
637			return AssertionResult{
638				Type:     "url_reachable",
639				Expected: fmt.Sprintf("%s reachable", check.URL),
640				Actual:   fmt.Sprintf("connection failed: %v", err),
641				Passed:   false,
642			}
643		}
644		expected := "any 2xx"
645		passed := is2xx(statusCode)
646		if check.StatusCode != nil {
647			expected = fmt.Sprintf("HTTP %d", *check.StatusCode)
648			passed = statusCode == *check.StatusCode
649		}
650		return AssertionResult{
651			Type:     "url_reachable",
652			Expected: expected,
653			Actual:   fmt.Sprintf("HTTP %d (%s)", statusCode, elapsed.Round(time.Millisecond)),
654			Passed:   passed,
655		}
656	}
657	
658	// CheckServiceReachable verifies an external service dependency is accessible.
659	func CheckServiceReachable(check *schema.ServiceReachableCheck) AssertionResult {
660		statusCode, elapsed, err := httpReachable(check.URL, check.Timeout.Duration, 0)
661		if err != nil {
662			return AssertionResult{
663				Type:     "service_reachable",
664				Expected: fmt.Sprintf("%s reachable", check.URL),
665				Actual:   fmt.Sprintf("connection failed: %v", err),
666				Passed:   false,
667			}
668		}
669		return AssertionResult{
670			Type:     "service_reachable",
671			Expected: "any 2xx",
672			Actual:   fmt.Sprintf("HTTP %d (%s)", statusCode, elapsed.Round(time.Millisecond)),
673			Passed:   is2xx(statusCode),
674		}
675	}
676	
677	// CheckS3Bucket verifies an S3-compatible bucket is accessible via anonymous HEAD.
678	func CheckS3Bucket(check *schema.S3BucketCheck) AssertionResult {
679		endpoint := check.Endpoint
680		if endpoint == "" {
681			endpoint = "s3.amazonaws.com"
682		}
683		var url string
684		if strings.HasPrefix(endpoint, "http://") || strings.HasPrefix(endpoint, "https://") {
685			url = fmt.Sprintf("%s/%s?location", endpoint, check.Bucket)
686		} else {
687			url = fmt.Sprintf("https://%s/%s?location", endpoint, check.Bucket)
688		}
689	
690		statusCode, elapsed, err := httpReachable(url, 5*time.Second, 0)
691		if err != nil {
692			return AssertionResult{
693				Type:     "s3_bucket",
694				Expected: fmt.Sprintf("bucket %s accessible", check.Bucket),
695				Actual:   fmt.Sprintf("connection failed: %v", err),
696				Passed:   false,
697			}
698		}
699		if statusCode == 403 {
700			return AssertionResult{
701				Type:     "s3_bucket",
702				Expected: fmt.Sprintf("bucket %s accessible", check.Bucket),
703				Actual:   "HTTP 403 Forbidden — bucket requires authentication; use http assertion with Go templates for authenticated access",
704				Passed:   false,
705			}
706		}
707		return AssertionResult{
708			Type:     "s3_bucket",
709			Expected: fmt.Sprintf("bucket %s accessible", check.Bucket),
710			Actual:   fmt.Sprintf("HTTP %d (%s)", statusCode, elapsed.Round(time.Millisecond)),
711			Passed:   is2xx(statusCode),
712		}
713	}
714	
715	// CheckVersion runs a shell command and regex-matches stdout.
716	func CheckVersion(check *schema.VersionCheck) AssertionResult {
717		ctx, cancel := context.WithTimeout(context.Background(), 10*time.Second)
718		defer cancel()
719	
720		cmd := exec.CommandContext(ctx, "sh", "-c", check.Command)
721		var stdout bytes.Buffer
722		cmd.Stdout = &stdout
723		err := cmd.Run()
724		if err != nil {
725			return AssertionResult{
726				Type:     "version_check",
727				Expected: fmt.Sprintf("pattern %q", check.Pattern),
728				Actual:   fmt.Sprintf("command failed: %v", err),
729				Passed:   false,
730			}
731		}
732	
733		re := regexp.MustCompile(check.Pattern)
734		output := strings.TrimSpace(stdout.String())
735		if re.MatchString(output) {
736			return AssertionResult{
737				Type:     "version_check",
738				Expected: fmt.Sprintf("pattern %q", check.Pattern),
739				Actual:   output,
740				Passed:   true,
741			}
742		}
743		return AssertionResult{
744			Type:     "version_check",
745			Expected: fmt.Sprintf("pattern %q", check.Pattern),
746			Actual:   fmt.Sprintf("output %q did not match", output),
747			Passed:   false,
748		}
749	}
